mapper.select:
SELECT q.id, q.course_id, q.section_id, q.user_id, q.question_title, q.question_content, q.answer_content, q.answer_user_id, q.answer_time, q.status, q.like_count, q.is_top, q.create_time, s.section_title, u1.nick_name as asker_name, u2.nick_name as answerer_name FROM osh_course_question q LEFT JOIN osh_course_section s ON q.section_id = s.id LEFT JOIN sys_user u1 ON q.user_id = u1.user_id LEFT JOIN sys_user u2 ON q.answer_user_id = u2.user_id WHERE q.course_id = #{courseId}
AND q.section_id = #{sectionId}
AND q.status = #{status}
ORDER BY q.is_top DESC, q.create_time DESC

mapper.insert:
INSERT INTO osh_course_question (
    course_id, section_id, user_id, question_title, question_content, status, create_time
) VALUES (
    #{courseId}, #{sectionId}, #{userId}, #{questionTitle}, #{questionContent}, 'pending', NOW()
)

mapper.update:
UPDATE osh_course_question
answer_content = #{answer_content}, answer_user_id = #{answer_user_id}, answer_time = #{answer_time}, status = #{status}, update_time = NOW()
WHERE id = #{id}
